const input = $input.item.json;
const body = input.body || {};

const user_id = input.user_id || body.user_id || '';
const week_number = parseInt(body.week_number) || 1;
const month = body.month || '';
const platforms = body.platforms || ['linkedin'];
const pipeline_run_id = body.pipeline_run_id || null;
const callback_url = body.callback_url || null;
const business_url = body.business_url || '';
const industry = body.industry || '';
const start_date = body.start_date || '';
const end_date = body.end_date || '';
const day_count = parseInt(body.day_count) || 7;
const content_language = body.content_language || 'English';
const campaign_theme = body.campaign_theme || '';
const brand_voice_notes = body.brand_voice_notes || '';
const brand_voice_traits = body.brand_voice_traits || [];

// Calculate step number: Week 1 = step 3, Week 4 = step 6
const step = week_number + 2;

return {
  json: {
    user_id,
    week_number,
    month,
    platforms,
    pipeline_run_id,
    callback_url,
    business_url,
    industry,
    start_date,
    end_date,
    day_count,
    content_language,
    campaign_theme,
    brand_voice_notes,
    brand_voice_traits,
    step
  }
};

const params = $('Extract Params').item.json;
const content_language = params.content_language || 'English';
const themeRaw = $('Read Theme').item.json;
const icpRaw = $('Read ICP').item.json;
const productsRaw = $('Read Products').item.json;
const weeklyTopicsRaw = $('Read Weekly Topics').item.json;

// Read brand context
const brandVoiceNotes = params.brand_voice_notes || '';
let brandDocSummary = '';
try {
  const brandDocsItems = $('Read Brand Docs').all();
  brandDocSummary = brandDocsItems
    .map(item => item.json.summary_text || '')
    .filter(Boolean)
    .join('\n---\n')
    .substring(0, 3000);
} catch(e) { /* no brand docs */ }

const themes = Array.isArray(themeRaw) ? themeRaw : [themeRaw];
const theme = themes[0] || {};
const campaign = theme.campaigns || {};
const campaign_id = campaign.id || theme.campaign_id || null;
const show_name = campaign.show_name || 'Content Series';
const theme_id = theme.id || null;
const theme_name = theme.theme_name || 'Weekly Theme';
const inspirational_theme = theme.inspirational_theme || '';

let weeklyTopics = [];
try {
  weeklyTopics = Array.isArray(weeklyTopicsRaw) ? weeklyTopicsRaw : [];
} catch(e) { weeklyTopics = []; }

let dailyAssignments = [];
if (weeklyTopics.length > 0) {
  dailyAssignments = weeklyTopics.map(wt => ({
    day_number: wt.day_number,
    topic: wt.topic || 'Engagement',
    content_angle: wt.content_angle || '',
    product_id: wt.product_id || null,
    product_name: wt.product_name || null
  }));
} else if (theme.content_types && Array.isArray(theme.content_types)) {
  dailyAssignments = theme.content_types;
} else if (typeof theme.content_types === 'string') {
  try { dailyAssignments = JSON.parse(theme.content_types); } catch(e) { dailyAssignments = []; }
}

const icps = Array.isArray(icpRaw) ? icpRaw : [icpRaw];
const icp = icps[0] || {};
const icp_summary = (icp.icp_summary || '').substring(0, 500);

const products = Array.isArray(productsRaw) ? productsRaw : (productsRaw ? [productsRaw] : []);
const productMap = {};
const productList = [];
for (const p of products) {
  if (p.id) {
    productMap[p.id] = p;
    productList.push({ id: p.id, name: p.name, description: p.description, image_url: p.image_url || null });
  }
}

const weekNum = params.week_number;
const platforms = params.platforms;
const month = params.month;

// ============================================================
// ALL 4 STORYTELLING FRAMEWORKS
// Each theme provides a complete 7-day narrative structure.
// The campaign_theme param selects which one to use.
// ============================================================

const storyFrameworks = {
  'luxury-intrigue': [
    { day: 1, label: 'Monday', theme: 'Curiosity Hook', goal: 'Stop the scroll with intrigue and visual mystery', concept: 'Introduce the piece through partial reveal, light reflection, or extreme macro details that spark curiosity', angle: 'Focus on mystery rather than immediate explanation', hooks: ['The detail most people never notice...', 'A piece that changes everything.', 'Look closer.'], driver: 'Curiosity increases watch time and replays' },
    { day: 2, label: 'Tuesday', theme: 'Craftsmanship', goal: 'Establish luxury credibility and authority', concept: 'Highlight craftsmanship behind the piece', angle: 'Show the making process or implied craftsmanship story', hooks: ['From raw material to wearable art.', 'Precision in every millimeter.', 'Crafted, not manufactured.'], driver: 'Craftsmanship content triggers fascination and trust' },
    { day: 3, label: 'Wednesday', theme: 'Meaning & Symbolism', goal: 'Build emotional connection', concept: 'Position jewelry as a symbol of moments, relationships, or personal identity', angle: 'Storytelling around meaning rather than product specs', hooks: ['Some pieces mark a moment forever.', 'Jewelry is never just jewelry.', 'Every piece tells a story.'], driver: 'Emotion increases saves and comments' },
    { day: 4, label: 'Thursday', theme: 'Transformation Moment', goal: 'Show the impact when the jewelry is worn', concept: 'The transformation from object to presence', angle: 'Reveal the moment the piece becomes part of identity or style', hooks: ['The moment everything changes.', 'From detail to statement.', 'Presence begins here.'], driver: 'Transformation visuals drive shares and engagement' },
    { day: 5, label: 'Friday', theme: 'Hidden Detail / Surprise', goal: 'Encourage shares through discovery', concept: 'Reveal something unexpected about the piece, gemstone, or design', angle: 'Educational but visually captivating facts', hooks: ['Most people never notice this.', 'The secret behind the sparkle.', 'Why this cut catches light differently.'], driver: 'Surprise drives sharing behavior' },
    { day: 6, label: 'Saturday', theme: 'Lifestyle Aspiration', goal: 'Inspire desire and aspiration', concept: 'Place jewelry in aspirational environments', angle: 'Luxury lifestyle storytelling', hooks: ['Luxury is a feeling.', 'Some moments deserve more.', 'Where elegance begins.'], driver: 'Aspirational content fuels desire' },
    { day: 7, label: 'Sunday', theme: 'Legacy & Timelessness', goal: 'Build brand prestige and long-term emotional value', concept: 'Jewelry as heirloom, tradition, and timeless symbol', angle: 'Focus on longevity, legacy, and generational value', hooks: ['Some pieces outlive trends.', 'Designed to last generations.', 'What will your story be?'], driver: 'Legacy messaging strengthens brand authority' }
  ],
  'emotional-journey': [
    { day: 1, label: 'Monday', theme: 'The Desire', goal: 'Spark longing with aspirational imagery', concept: 'Show the object of desire in its most magnetic form — warm light on gold, a diamond catching flame, a hand reaching but not yet touching', angle: 'Aspiration over possession — make the viewer feel the pull before they understand why', hooks: ['You knew the moment you saw it.', 'Some things find you before you find them.', 'This is where wanting begins.'], driver: 'Desire is the strongest purchase initiator — aspirational imagery triggers dopamine and increases save rates' },
    { day: 2, label: 'Tuesday', theme: 'The Story Behind', goal: 'Build narrative depth and brand authenticity', concept: 'Origin story of the piece — the sketch that started it, the mine where the stone was found, the moment of inspiration', angle: 'Backstory creates perceived value — the longer the origin story, the more precious the object feels', hooks: ['Every piece begins as a whisper.', 'Before it was yours, it was a dream on paper.', 'The story started long before the stone was set.'], driver: 'Origin stories increase perceived value — story-driven content gets 22x more engagement than facts alone' },
    { day: 3, label: 'Wednesday', theme: 'The Person', goal: 'Create relatability and social proof through real human connection', concept: 'Feature a real person — customer, founder, or artisan. Show the piece as part of someone\'s actual life, not a catalog', angle: 'People buy from people — humanize the brand through authentic portraiture', hooks: ['She never takes it off.', 'Ask her about the ring. She will tell you everything.', 'This is not a model. This is a moment.'], driver: 'Person-centered content generates 6.9x higher engagement — social proof reduces purchase anxiety' },
    { day: 4, label: 'Thursday', theme: 'The Ritual', goal: 'Embed the product into daily life and create habitual association', concept: 'The quiet ritual of putting on jewelry — morning routines, getting ready, the last thing before leaving', angle: 'Luxury as daily ritual, not special occasion — normalize the extraordinary', hooks: ['The first thing she reaches for.', 'A ritual that never gets old.', 'Every morning begins with this.'], driver: 'Ritual content creates habitual mental associations — strongest predictor of purchase intent' },
    { day: 5, label: 'Friday', theme: 'The Confidence', goal: 'Show the emotional transformation that wearing the piece creates', concept: 'Before/after energy — not physical but psychological. Posture change, eye contact, the way someone enters a room differently', angle: 'Jewelry as confidence catalyst — the piece does not just decorate, it activates', hooks: ['She wore it and the room noticed.', 'Confidence is not born. It is worn.', 'The moment you stop adjusting and start owning.'], driver: 'Transformation content is the #1 driver of shares — viewers tag friends with "this is you"' },
    { day: 6, label: 'Saturday', theme: 'The Celebration', goal: 'Associate the brand with life\'s peak emotional moments', concept: 'Milestones, gifts, surprises, anniversaries, proposals, promotions. The piece as witness to the moment that matters most', angle: 'Jewelry as emotional anchor — the physical object that holds the memory', hooks: ['Some nights deserve forever.', 'The gift she will never forget.', 'This is the piece that was there.'], driver: 'Celebration content triggers the strongest emotional response and highest comment engagement' },
    { day: 7, label: 'Sunday', theme: 'The Promise', goal: 'Create forward-looking emotional resonance and long-term brand connection', concept: 'Heirloom energy — the piece passing through generations, the promise of "always," the commitment embedded in precious materials', angle: 'Luxury as legacy and emotional covenant — the piece outlasts the moment', hooks: ['What will you pass down?', 'Made for now. Meant for always.', 'A promise you can hold.'], driver: 'Legacy content builds deepest brand authority — frames purchase as investment in identity' }
  ],
  'authority-educator': [
    { day: 1, label: 'Monday', theme: 'Industry Myth-Bust', goal: 'Stop the scroll with a provocative claim that challenges conventional wisdom', concept: 'Take a widely believed fact about jewelry or luxury and dismantle it with evidence. Be direct, confident, contrarian', angle: 'Contrarian authority — the brand knows what others get wrong', hooks: ['Everything you were told about diamonds is wrong.', 'Stop falling for this.', 'The industry does not want you to know this.'], driver: 'Myth-busting triggers the knowledge gap — contrarian content generates 2x more comments' },
    { day: 2, label: 'Tuesday', theme: 'Material Deep-Dive', goal: 'Educate on materials, gems, metals, or techniques to build informed desire', concept: 'Extreme close-up education — molecular structure of a diamond, why 18k gold behaves differently than 14k, how sapphire forms over millions of years', angle: 'Scientific wonder wrapped in beauty — make education feel like discovery', hooks: ['This took 3 billion years to form.', 'The difference you can feel but never see.', 'Why this metal changes everything.'], driver: 'Educational content is the #1 type saved on Instagram — material knowledge reduces purchase anxiety' },
    { day: 3, label: 'Wednesday', theme: 'Design Philosophy', goal: 'Reveal the intentionality behind every design decision', concept: 'Why a piece looks the way it does — proportions, negative space, influences from architecture or art. Show sketches next to finished pieces', angle: 'Design thinking as luxury differentiator — every curve has a reason', hooks: ['Nothing about this is accidental.', 'The line you never notice that changes everything.', 'We designed this 47 times before it was right.'], driver: 'Showing the creative process triggers the labor illusion — knowing how hard it was makes it feel more valuable' },
    { day: 4, label: 'Thursday', theme: 'Insider Knowledge', goal: 'Share exclusive expertise that only industry insiders possess', concept: 'Tips and secrets jewelers use but consumers never hear — how to spot quality at a glance, what to look for under a loupe, how professionals evaluate color', angle: 'Exclusive access to expert knowledge — the viewer becomes the insider', hooks: ['What jewelers check first and never tell you.', 'The test that takes 3 seconds and tells you everything.', 'After this, you will never look at jewelry the same way.'], driver: 'Insider knowledge triggers the exclusivity principle — highest save-to-impression ratio content type' },
    { day: 5, label: 'Friday', theme: 'Comparison / Breakdown', goal: 'Build confidence through transparent visual comparison', concept: 'Side-by-side breakdowns — lab vs natural diamonds, hollow vs solid construction, machine-set vs hand-set stones. Split-screen, macro details, cross-sections', angle: 'Transparent comparison as confidence builder — the brand has nothing to hide', hooks: ['Same price. Completely different quality.', 'Put them side by side. The truth is obvious.', 'This is what you are actually paying for.'], driver: 'Comparison content resolves the #1 luxury purchase barrier: "is it really worth it?"' },
    { day: 6, label: 'Saturday', theme: 'Trend Forecast', goal: 'Position the brand as a forward-looking authority that shapes taste', concept: 'What is emerging, what is fading, what is next. Upcoming materials, design movements, cultural shifts in how people wear jewelry', angle: 'Tastemaker authority — the brand sees what is coming before anyone else', hooks: ['This will be everywhere in 6 months.', 'The trend no one is talking about yet.', 'What the next generation of luxury looks like.'], driver: 'Trend content gets shared because sharing predictions signals social currency' },
    { day: 7, label: 'Sunday', theme: 'Heritage & Legacy', goal: 'Anchor brand authority in history, tradition, and timeless principles', concept: 'History behind techniques, materials, design movements. How ancient goldsmiths solved problems still used today', angle: 'Timeless authority — the brand stands on centuries of accumulated wisdom', hooks: ['This technique is 4,000 years old. We still use it.', 'Some things were perfected long before us.', 'The oldest rule in jewelry still holds.'], driver: 'Heritage content builds the deepest form of brand authority — signals permanence and seriousness' }
  ],
  'cinematic-series': [
    { day: 1, label: 'Monday', theme: 'Cold Open / Teaser', goal: 'Drop viewers into a visual moment with zero context — maximum intrigue', concept: 'Open in medias res — close-up of light hitting a stone, a velvet box being opened by unknown hands, a piece being placed on skin with no face shown', angle: 'Cold open technique — hook before context, mystery before meaning', hooks: ['No caption needed.', 'Wait for it.', 'Monday. Episode begins.'], driver: 'Cold opens reduce skip rate by 35% — the Zeigarnik effect compels viewers to follow for resolution' },
    { day: 2, label: 'Tuesday', theme: 'The Reveal', goal: 'Pay off Monday\'s mystery with the full dramatic reveal', concept: 'The answer to "what was that?" — full piece reveal in glory. Wide shot after the macro, context after the mystery, the 360-degree spin', angle: 'Payoff architecture — the reveal is only as powerful as the setup that preceded it', hooks: ['Now you see it.', 'This is what Monday was hiding.', 'The full picture.'], driver: 'The reveal satisfies Day 1 tension — this dopamine release keeps viewers coming back weekly' },
    { day: 3, label: 'Wednesday', theme: 'Behind the Scenes', goal: 'Pull back the curtain on creation to deepen appreciation', concept: 'Show the making — the workshop, the tools, the hands at work, the CAD design, the wax model, the casting, the stone setting', angle: 'Access as privilege — showing the process makes the viewer feel like an insider', hooks: ['You were not supposed to see this.', 'Before it was beautiful, it was this.', '36 hours of work in 30 seconds.'], driver: 'BTS content activates the labor illusion — seeing effort increases perceived value' },
    { day: 4, label: 'Thursday', theme: 'The Moment', goal: 'Capture the dramatic peak — the emotional climax of the episode', concept: 'The hero shot — the unboxing, the first time worn, the reaction, the gasp, the mirror moment. Cinematic pacing: slow build, then the moment hits', angle: 'Peak emotion as content climax — build tension then deliver catharsis', hooks: ['This is the moment.', 'Watch her face.', 'Some moments change everything.'], driver: 'Peak emotional moments are the most shared content type — reaction content triggers mirror neurons' },
    { day: 5, label: 'Friday', theme: 'Plot Twist', goal: 'Surprise the audience with an unexpected angle or hidden feature', concept: 'Subvert expectations — show the piece in an unexpected context, reveal a hidden feature like a secret engraving or convertible design, flip the camera', angle: 'Surprise as engagement multiplier — the brain pays more attention after being surprised', hooks: ['You did not see this coming.', 'Turn it over.', 'Not what you expected.'], driver: 'Surprise content generates the highest share rate — unexpected moments trigger the social sharing reflex' },
    { day: 6, label: 'Saturday', theme: 'The World', goal: 'Build the cinematic universe — place the piece in a world worth inhabiting', concept: 'World-building — the piece in its natural habitat. A candlelit dinner, a rooftop at golden hour, an art gallery opening, a rain-soaked Paris street', angle: 'Lifestyle as set design — the piece belongs in a world the viewer aspires to', hooks: ['Welcome to the world.', 'Where this piece lives.', 'Step inside.'], driver: 'Aspirational lifestyle content drives desire through environmental storytelling — viewers want the life, not just the piece' },
    { day: 7, label: 'Sunday', theme: 'Next Episode Teaser', goal: 'Create a cliffhanger that guarantees return next Monday', concept: 'A 5-second flash of next week\'s piece — out of focus, partially obscured, shot through glass, a shadow. Just enough to trigger recognition without confirmation', angle: 'Cliffhanger mechanics — end on an open loop that can only be closed by returning', hooks: ['Next week changes everything.', 'You are not ready for what is coming.', 'To be continued.'], driver: 'Cliffhangers exploit the Zeigarnik effect at maximum strength — highest "turn-on-notifications" behavior' }
  ]
};

// Select framework based on campaign_theme from frontend
const campaign_theme = params.campaign_theme || theme.theme_name || 'luxury-intrigue';
const storyFramework = storyFrameworks[campaign_theme];
if (!storyFramework) {
  throw new Error('Unknown campaign_theme: "' + campaign_theme + '". Valid themes: ' + Object.keys(storyFrameworks).join(', '));
}

const platformRules = [];
for (const plat of platforms) {
  const p = plat.toLowerCase();
  if (p === 'linkedin') platformRules.push('- LinkedIn: 1300-1800 chars, thought leadership tone, line breaks between paragraphs, 3-5 professional hashtags, product CTA');
  if (p === 'instagram') platformRules.push('- Instagram: 150-300 char caption, 20-30 hashtags in separate first_comment field, emoji allowed, product CTA. Video will be generated from product image.');
  if (p === 'x') platformRules.push('- X: Single tweet under 280 chars, punchy and conversational, product CTA, 3-5 hashtags');
  if (p === 'youtube') platformRules.push('- YouTube: Write a video CAPTION (150-300 chars) for the YouTube Short post description. Also include title, hashtags, cta. Do NOT include scene breakdowns or video scripts in the caption. Video generated from actual product image.');
  if (p === 'tiktok') platformRules.push('- TikTok: Short punchy caption (100-200 chars), trending hashtags, casual/fun tone, product CTA. Video will be generated from product image.');
  if (p === 'facebook') platformRules.push('- Facebook: 200-400 char post, conversational tone, emoji-friendly, product CTA, 3-5 hashtags.');
}

const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

const dayDescriptions = [];
const dayMeta = [];
for (let dayIdx = 0; dayIdx < 7; dayIdx++) {
  const dayNumber = dayIdx + 1;
  const framework = storyFramework[dayIdx];
  const assignment = dailyAssignments[dayIdx] || {};
  const product_id = assignment.product_id || null;
  const product = product_id ? (productMap[product_id] || {}) : {};
  const product_name = assignment.product_name || product.name || 'Featured Product';
  const product_description = product.description || '';
  const product_image_url = product.image_url || null;
  const topic = assignment.topic || framework.theme;
  const content_angle = assignment.content_angle || framework.angle;

  let scheduledDate = '';
  let startDateObj;
  if (params.start_date) {
    startDateObj = new Date(params.start_date + 'T00:00:00');
  } else {
    startDateObj = new Date();
    startDateObj.setHours(0, 0, 0, 0);
  }
  const targetDate = new Date(startDateObj);
  targetDate.setDate(startDateObj.getDate() + (dayNumber - 1));
  const sy = targetDate.getFullYear();
  const sm = String(targetDate.getMonth() + 1).padStart(2, '0');
  const sd = String(targetDate.getDate()).padStart(2, '0');
  scheduledDate = sy + '-' + sm + '-' + sd;
  const actualDayName = dayNames[targetDate.getDay()];

  dayDescriptions.push(
    'Day ' + dayNumber + ' (' + actualDayName + ' - ' + framework.theme + '):\n' +
    '  Goal: ' + framework.goal + '\n' +
    '  Concept: ' + framework.concept + '\n' +
    '  Angle: ' + framework.angle + '\n' +
    '  Hooks: "' + framework.hooks.join('", "') + '"\n' +
    '  Driver: ' + framework.driver + '\n' +
    '  Product: ' + product_name + ' -- ' + product_description + '\n' +
    '  Topic: "' + topic + '"\n' +
    '  Angle: "' + content_angle + '"'
  );
  dayMeta.push({ day_number: dayNumber, product_id, product_name, product_description, product_image_url, topic, content_angle, scheduled_date: scheduledDate });
}

const platSchemas = [];
for (const plat of platforms) {
  const p = plat.toLowerCase();
  if (p === 'linkedin') platSchemas.push('"linkedin": { "text": "...", "hashtags": [...], "cta": "..." }');
  if (p === 'instagram') platSchemas.push('"instagram": { "text": "...", "hashtags": [...], "first_comment": "...", "cta": "..." }');
  if (p === 'x') platSchemas.push('"x": { "text": "...", "hashtags": [...], "cta": "..." }');
  if (p === 'youtube') platSchemas.push('"youtube": { "caption": "...", "title": "...", "hashtags": [...], "cta": "..." }');
  if (p === 'tiktok') platSchemas.push('"tiktok": { "text": "...", "hashtags": [...], "cta": "..." }');
  if (p === 'facebook') platSchemas.push('"facebook": { "text": "...", "hashtags": [...], "cta": "..." }');
}

const megaPrompt = 'CRITICAL LANGUAGE REQUIREMENT: Generate ALL content exclusively in ' + content_language + '. Every word, caption, and hashtag must be in ' + content_language + '. No mixing languages. This is non-negotiable.\n\n' +
'You are a luxury brand content strategist. Generate social media content for ALL 7 days following the Viral Storytelling Framework.\n\n' +
'=== STORYTELLING FRAMEWORK ===\n' +
'Weekly rhythm: ' + storyFramework.map(f => f.theme).join(' > ') + '\n\n' +
'=== CONTEXT ===\n' +
'Show: "' + show_name + '"\n' +
'Season ' + weekNum + ': "' + theme_name + '" -- ' + inspirational_theme + '\n' +
'ICP: ' + icp_summary + '\n' +
(brandVoiceNotes ? 'Brand Voice (from client): ' + brandVoiceNotes + '\n' : '') +
(brandDocSummary ? 'Brand Guidelines:\n' + brandDocSummary + '\n' : '') +
'Platforms: ' + platforms.join(', ') + '\n\n' +
'=== VIDEO NOTE ===\n' +
'For Instagram and YouTube, videos will use the ACTUAL PRODUCT IMAGE. Scripts should describe content anchored to real product photos.\n\n' +
'=== 7-DAY PLAN ===\n\n' +
dayDescriptions.join('\n\n') + '\n\n' +
'=== PLATFORM RULES ===\n' +
platformRules.join('\n') + '\n\n' +
'=== OUTPUT FORMAT ===\n' +
'Return JSON: { "days": [ { "day_number": 1, "storytelling_theme": "' + storyFramework[0].theme + '", "posts": { ' + platSchemas.join(', ') + ' }, "image_prompt": "Detailed AI image prompt for this day (max 500 chars)" }, ... (all 7 days) ] }\n' +
'Include ALL platforms for EVERY day. Do not skip any.\n\nREMINDER: ALL output must be in ' + content_language + ' only. No exceptions.';

return {
  json: {
    prompt: megaPrompt,
    day_meta: dayMeta,
    user_id: params.user_id,
    campaign_id,
    theme_id,
    show_name,
    theme_name,
    week_number: weekNum,
    platforms,
    pipeline_run_id: params.pipeline_run_id,
    callback_url: params.callback_url,
    step: params.step,
    icp_summary,
    inspirational_theme
  }
};

const ctx = $('Prepare Daily Content Loop').item.json;
const claudeResponse = $input.item.json;
let raw = '';
if (claudeResponse.content && claudeResponse.content[0]) raw = claudeResponse.content[0].text;
else if (typeof claudeResponse === 'string') raw = claudeResponse;

let parsed;
try { parsed = JSON.parse(raw); } catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try { parsed = JSON.parse(stripped); } catch(e2) {
    const match = stripped.match(/[\[{][\s\S]*[\]}]/);
    if (match) { try { parsed = JSON.parse(match[0]); } catch(e3) { parsed = { days: [] }; } }
    else { parsed = { days: [] }; }
  }
}

const days = parsed.days || [];
const dayMeta = ctx.day_meta || [];
const platforms = ctx.platforms || [];
const allContentItems = [];
for (const day of days) {
  const dayNum = day.day_number || 0;
  const meta = dayMeta.find(m => m.day_number === dayNum) || dayMeta[dayNum - 1] || {};
  const posts = day.posts || {};
  const image_prompt = day.image_prompt || 'Professional product lifestyle image, photorealistic, 1:1';
  for (const platform of platforms) {
    const plat = platform.toLowerCase();
    const post = posts[plat] || {};
    allContentItems.push({
      user_id: ctx.user_id, campaign_id: ctx.campaign_id, theme_id: ctx.theme_id,
      title: ctx.show_name + ' S' + ctx.week_number + ' Day ' + dayNum + ' - ' + plat,
      content: plat === 'youtube' ? (post.caption || post.text || JSON.stringify(post)) : (post.text || JSON.stringify(post)),
      content_type: 'text', platform: plat, scheduled_date: meta.scheduled_date || '',
      status: 'pending_review', image_prompt, product_id: meta.product_id || null,
      hashtags: post.hashtags || [], first_comment: post.first_comment || null
    });
  }
}
return { json: { content_items: allContentItems, content_count: allContentItems.length, user_id: ctx.user_id, campaign_id: ctx.campaign_id, week_number: ctx.week_number, pipeline_run_id: ctx.pipeline_run_id, callback_url: ctx.callback_url, step: ctx.step } };

const data = $input.item.json;
const allItems = data.content_items || [];
const batchBody = allItems.map(item => ({
  user_id: item.user_id, campaign_id: item.campaign_id, theme_id: item.theme_id,
  title: item.title, content: item.content, content_type: item.content_type || 'text',
  platform: item.platform, scheduled_date: item.scheduled_date, status: 'pending_review',
  image_prompt: item.image_prompt || null, product_id: item.product_id || null,
  hashtags: item.hashtags && item.hashtags.length > 0 ? `{${item.hashtags.map(h => `"${h.replace(/\"/g, '\\\\"')}"`).join(',')}}` : null,
  first_comment: item.first_comment || null
}));
return { json: { batch_body: batchBody, batch_count: batchBody.length, user_id: data.user_id, campaign_id: data.campaign_id, week_number: data.week_number, pipeline_run_id: data.pipeline_run_id, callback_url: data.callback_url, step: data.step } };

const batchData = $('Prepare Batch Insert').item.json;
if (!batchData.callback_url) return [];
return { json: { pipeline_run_id: batchData.pipeline_run_id, callback_url: batchData.callback_url, step: batchData.step, week_number: batchData.week_number, batch_count: batchData.batch_count } };

const allItems = [];
